cat <<'EOF' > csv-parser.ts
export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

class CSVResultImpl implements CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];

  constructor(rows: Array<Record<string, any>>, headers: string[], errors: CSVError[]) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
    return new CSVResultImpl(this.rows.filter(predicate), [...this.headers], this.errors);
  }

  sum(column: string): number {
    return this.rows.reduce((total, row) => {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        return total + value;
      }
      return total;
    }, 0);
  }

  average(column: string): number {
    let count = 0;
    const total = this.rows.reduce((sum, row) => {
      const value = row[column];
      if (typeof value === 'number' && !Number.isNaN(value)) {
        count += 1;
        return sum + value;
      }
      return sum;
    }, 0);
    return count === 0 ? 0 : total / count;
  }

  count(): number {
    return this.rows.length;
  }

  groupBy(column: string): Map<any, Record<string, any>[]> {
    const map = new Map<any, Record<string, any>[]>();
    for (const row of this.rows) {
      const key = row[column];
      if (!map.has(key)) {
        map.set(key, []);
      }
      map.get(key)!.push(row);
    }
    return map;
  }
}

function coerceValue(raw: string): any {
  const trimmed = raw.trim();
  if (trimmed === '') {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }
  if (lower === 'true') {
    return true;
  }
  if (lower === 'false') {
    return false;
  }
  const numeric = Number(trimmed);
  if (!Number.isNaN(numeric) && trimmed !== '' && isFinite(numeric)) {
    return numeric;
  }
  return trimmed;
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';
  const normalizedInput = options.lineSeparator
    ? input
    : input.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  const headers: string[] = [];
  const rows: Record<string, any>[] = [];
  const errors: CSVError[] = [];

  let rowFields: string[] = [];
  let fieldBuffer = '';
  let inQuotes = false;
  let currentRowNumber = 1;
  let headerSet = false;

  const lineSepLength = lineSeparator.length;

  const pushField = () => {
    rowFields.push(fieldBuffer);
    fieldBuffer = '';
  };

  const finalizeRow = () => {
    const fields = [...rowFields];
    rowFields = [];
    const rowNumber = currentRowNumber;

    if (!headerSet) {
      headerSet = true;
      headers.length = 0;
      headers.push(...fields);
      currentRowNumber += 1;
      return;
    }

    if (headers.length !== fields.length) {
      errors.push({
        row: rowNumber,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
    }

    const rowObject: Record<string, any> = {};
    headers.forEach((header, index) => {
      const rawValue = index < fields.length ? fields[index] : '';
      rowObject[header] = coerceValue(rawValue);
    });
    rows.push(rowObject);
    currentRowNumber += 1;
  };

  const inputLength = normalizedInput.length;
  let index = 0;

  while (index < inputLength) {
    const char = normalizedInput[index];

    if (inQuotes) {
      if (char === quote) {
        const nextChar = normalizedInput[index + 1];
        if (nextChar === quote) {
          fieldBuffer += quote;
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }
      fieldBuffer += char;
      index += 1;
      continue;
    }

    if (char === quote) {
      inQuotes = true;
      index += 1;
      continue;
    }

    if (
      lineSepLength > 0 &&
      normalizedInput.substring(index, index + lineSepLength) === lineSeparator
    ) {
      pushField();
      finalizeRow();
      index += lineSepLength;
      continue;
    }

    if (char === delimiter) {
      pushField();
      index += 1;
      continue;
    }

    fieldBuffer += char;
    index += 1;
  }

  if (inQuotes) {
    errors.push({
      row: currentRowNumber,
      message: 'Unterminated quoted field',
    });
  }

  const hasPendingData = fieldBuffer !== '' || rowFields.length > 0;
  if (hasPendingData) {
    pushField();
    finalizeRow();
  } else if (!headerSet && inputLength === 0) {
    // no header row, keep headers empty
    headerSet = true;
    headers.length = 0;
  }

  return new CSVResultImpl(rows, headers, errors);
}
