cat <<'EOF' > csv-parser.test.ts
import { parseCSV } from './csv-parser';

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual(actual: any, expected: any, message: string): void {
  if (actual !== expected) {
    throw new Error(`Assertion failed (${message}): expected ${expected}, got ${actual}`);
  }
}

function assertDeepEqual(actual: any, expected: any, message: string): void {
  const actualSerialized = JSON.stringify(actual);
  const expectedSerialized = JSON.stringify(expected);
  if (actualSerialized !== expectedSerialized) {
    throw new Error(`Assertion failed (${message}):
Expected: ${expectedSerialized}
Actual:   ${actualSerialized}`);
  }
}

function runTests(): void {
  // Basic parsing
  const basic = parseCSV('name,age\nAlice,30\nBob,25');
  assertDeepEqual(basic.headers, ['name', 'age'], 'basic headers');
  assertEqual(basic.rows.length, 2, 'basic row count');
  assertEqual(basic.rows[0].name, 'Alice', 'basic row 1 name');
  assertEqual(basic.rows[0].age, 30, 'basic row 1 age');
  assertEqual(basic.rows[1].age, 25, 'basic row 2 age');

  // Quoted fields containing commas
  const quoted = parseCSV('name,description\n"Widget","Large, heavy"\n"Gadget","Small, light"');
  assertEqual(quoted.rows.length, 2, 'quoted row count');
  assertEqual(quoted.rows[0].description, 'Large, heavy', 'quoted contains comma');

  // Escaped quotes inside quoted fields
  const escapeTest = parseCSV('speaker,quote\nBob,"He said ""Hello"" to me"');
  assertEqual(escapeTest.rows[0].quote, 'He said "Hello" to me', 'escaped quotes preserved');

  // Custom delimiter, quote, and line separator
  const custom = parseCSV("name|value|note;;'Widget'|10|'Complex; note'", {
    delimiter: '|',
    quote: "'",
    lineSeparator: ';;',
  });
  assertDeepEqual(custom.headers, ['name', 'value', 'note'], 'custom headers');
  assertEqual(custom.rows.length, 1, 'custom rows');
  assertEqual(custom.rows[0].note, 'Complex; note', 'custom quote');

  // Type coercion
  const typeCSV = parseCSV(
    'number,bool,nullval,empty,string\n42,TRUE,null,,hello\n3.14,false,NULL,"","  spaced  "'
  );
  assertEqual(typeCSV.rows[0].number, 42, 'integer coercion');
  assertEqual(typeCSV.rows[1].number, 3.14, 'float coercion');
  assertEqual(typeCSV.rows[0].bool, true, 'boolean true');
  assertEqual(typeCSV.rows[1].bool, false, 'boolean false');
  assertEqual(typeCSV.rows[0].nullval, null, 'null literal');
  assertEqual(typeCSV.rows[1].nullval, null, 'NULL literal');
  assertEqual(typeCSV.rows[0].empty, null, 'empty string to null');
  assertEqual(typeCSV.rows[1].empty, null, 'quoted empty string to null');
  assertEqual(typeCSV.rows[0].string, 'hello', 'string preserved');
  assertEqual(typeCSV.rows[1].string, 'spaced', 'string trimmed');

  // Malformed rows (mismatched field counts)
  const malformed = parseCSV('a,b\n1\n2,3,4');
  assertEqual(malformed.errors.length, 2, 'malformed row count');
  assertEqual(malformed.errors[0].row, 2, 'first malformed row number');
  assertEqual(malformed.errors[1].row, 3, 'second malformed row number');

  // Filtering
  const filterCSV = parseCSV('name,active\nAlice,true\nBob,false');
  const filtered = filterCSV.filter((row) => row.active === true);
  assertEqual(filtered.rows.length, 1, 'filter matches one row');
  assertEqual(filtered.rows[0].name, 'Alice', 'filter returns correct row');

  // Aggregations
  const agg = parseCSV(
    'group,item,value\nA,Alpha,10\nB,Beta,20\nA,Gamma,30\nB,Delta,NaN\nC,Epsilon,\nA,Zeta,40'
  );
  assertEqual(agg.sum('value'), 100, 'sum ignores NaN/null');
  assertEqual(agg.average('value'), 25, 'average computed');
  assertEqual(agg.count(), 6, 'count total rows');
  const grouped = agg.groupBy('group');
  assertEqual(grouped.size, 3, 'grouped keys');
  assertEqual(grouped.get('A')?.length ?? 0, 3, 'group A count');
  assertEqual(grouped.get('C')?.length ?? 0, 1, 'group C count');

  // Edge cases
  const empty = parseCSV('');
  assertEqual(empty.headers.length, 0, 'empty headers');
  assertEqual(empty.rows.length, 0, 'empty rows');
  assertEqual(empty.errors.length, 0, 'empty errors');

  const singleColumn = parseCSV('only\nvalue');
  assertEqual(singleColumn.headers.length, 1, 'single header');
  assertEqual(singleColumn.rows[0].only, 'value', 'single column value');

  const singleRow = parseCSV('col1,col2');
  assertEqual(singleRow.count(), 0, 'no data rows');

  const largeField = 'x'.repeat(5000);
  const largeCSV = parseCSV(`title,description\nLarge,"${largeField}, with extra text"`);
  assertEqual(largeCSV.rows[0].description, `${largeField}, with extra text`, 'large field parsed');
}

runTests();
console.log('All CSV parser tests passed.');
